// ============================================
// Extrai dados relevantes do payload da Evolution API
// Formato: messages.upsert event
// ============================================

const body = $input.first().json.body;

// Ignora mensagens que não são do tipo esperado
if (!body || !body.data) {
  return [{ json: { ignore: true, reason: 'no_data' } }];
}

const data = body.data;
const event = body.event;

// Só processa messages.upsert
if (event !== 'messages.upsert') {
  return [{ json: { ignore: true, reason: 'not_message_event', event } }];
}

const message = data.message;
const key = data.key;

// Mensagem enviada pelo operador via app do WhatsApp (operador assumiu o chat)
if (key.fromMe === true) {
  return [{ json: {
    ignore: true,
    isOperatorTakeover: true,
    reason: 'from_me',
    remoteJid: key.remoteJid
  } }];
}

// Ignora mensagens de grupo
if (key.remoteJid.includes('@g.us')) {
  return [{ json: { ignore: true, reason: 'group_message' } }];
}

// Ignora status broadcasts
if (key.remoteJid === 'status@broadcast') {
  return [{ json: { ignore: true, reason: 'status_broadcast' } }];
}

// Extrai conteúdo da mensagem
let messageContent = '';
let messageType = 'text';
let contactName = null;
let contactPhone = null;

if (message.conversation) {
  messageContent = message.conversation;
} else if (message.extendedTextMessage?.text) {
  messageContent = message.extendedTextMessage.text;
} else if (message.imageMessage?.caption) {
  messageContent = message.imageMessage.caption;
  messageType = 'image';
} else if (message.audioMessage) {
  messageContent = '[audio]';
  messageType = 'audio';
} else if (message.documentMessage) {
  messageContent = '[document]';
  messageType = 'document';
} else if (message.reactionMessage) {
  messageContent = message.reactionMessage.text || '';
  messageType = 'reaction';
} else if (message.contactMessage) {
  // Recepção compartilhou contato do gestor via vCard — missão cumprida
  const contact = message.contactMessage;
  const vcard = contact.vcard || '';
  // Extrai número WhatsApp do vCard: TEL;waid=5511982044215:+55 11 ...
  const waidMatch = vcard.match(/waid=(\d+)/);
  contactPhone = waidMatch ? waidMatch[1] : '';
  contactName = contact.displayName || '';
  messageType = 'contact';
  messageContent = `[contato compartilhado: ${contactName}${contactPhone ? ' | +' + contactPhone : ''}]`;
} else {
  // Tipo de mensagem não suportado
  return [{ json: { ignore: true, reason: 'unsupported_message_type' } }];
}

// Monta payload limpo
return [{
  json: {
    ignore: false,
    remoteJid: key.remoteJid,
    pushName: data.pushName || '',
    wamid: key.id,
    messageContent: messageContent.trim(),
    messageType,
    contactName,
    contactPhone,
    instanceName: body.instance || '',
    timestamp: data.messageTimestamp || Math.floor(Date.now() / 1000),
    // Número limpo (sem @s.whatsapp.net)
    phoneNumber: key.remoteJid.replace('@s.whatsapp.net', '')
  }
}];

