// Merge dados da mensagem com dados da conversa
const message = $('Parse Evolution Payload').first().json;
const dbResults = $input.first().json;

return [{
  json: {
    ...message,
    conversationId: dbResults.id || null,
    fastapiSessionId: dbResults.fastapi_session_id || null,
    currentStatus: dbResults.status || null,
    clinicName: dbResults.clinic_name || '',
    clinicPhone: dbResults.clinic_phone || message.remoteJid,
    paused: dbResults.paused || false,
    botBypassAttempts: dbResults.bot_bypass_attempts || 0,
    botBypassCooldownUntil: dbResults.bot_bypass_cooldown_until || null,
    sdrName: $('Supabase - Lê Config').first().json.sdr_name || 'Vera',
    detectedPersona: dbResults.detected_persona || null,
    personaConfidence: dbResults.persona_confidence || null,
    isHomolog: dbResults.is_homolog || false
  }
}];

// Prepara contexto unificado após criar/atualizar conversa
const messageData = $('Merge - Contexto da Conversa').first().json;
const dbResult = $input.first().json;

const conversationId = dbResult.id || messageData.conversationId;

return [{
  json: {
    conversationId,
    remoteJid: messageData.remoteJid,
    pushName: messageData.pushName,
    messageContent: messageData.messageContent,
    messageType: messageData.messageType,
    phoneNumber: messageData.phoneNumber,
    wamid: messageData.wamid,
    isNewConversation: messageData.isNewConversation,
    fastapiSessionId: messageData.fastapiSessionId,
    instanceName: messageData.instanceName,
    clinicName: messageData.clinicName,
    clinicPhone: messageData.clinicPhone,
    sdrName: messageData.sdrName || 'SDR',
    detectedPersona: messageData.detectedPersona || null,
    personaConfidence: messageData.personaConfidence || null,
    isHomolog: messageData.isHomolog || false
  }
}];

// ============================================
// Monta payload para o FastAPI conforme contrato real
// ============================================

const context = $('Prepara Contexto Unificado').first().json;
const historyRows = $('Supabase - Salva Inbound e Busca Histórico').all();

// Monta conversation_history como array de objetos
const conversationHistory = historyRows
  .filter(item => item.json && item.json.content)
  .map(item => ({
    role: item.json.direction === 'inbound' ? 'human' : 'agent',
    content: item.json.content,
    ...(item.json.stage ? { stage: item.json.stage } : {})
  }));

// Calcula attempt_count:
// - menu_bot: conta só outbounds com stage 'handling_objection' (tentativas de bypass)
// - outros: conta todos os outbounds
const detectedPersona = context.detectedPersona || null;
const outbounds = historyRows.filter(item => item.json && item.json.direction === 'outbound');
const attemptCount = detectedPersona === 'menu_bot'
  ? outbounds.filter(item => item.json.stage === 'handling_objection').length
  : outbounds.length;

return [{
  json: {
    clinicName: context.clinicName || '',
    clinicPhone: context.clinicPhone || context.phoneNumber,
    conversationHistory: conversationHistory,
    latestMessage: context.messageContent,
    detectedPersona: detectedPersona,
    personaConfidence: context.personaConfidence || null,
    attemptCount: attemptCount,
    // Dados preservados para os próximos nodes
    conversationId: context.conversationId,
    remoteJid: context.remoteJid,
    instanceName: context.instanceName,
    pushName: context.pushName,
    phoneNumber: context.phoneNumber,
    sdrName: context.sdrName || 'Vera',
    isHomolog: context.isHomolog || false
  }
}];

// ============================================
// Processa resposta do FastAPI - Contrato Real
// Response: {
//   response_message: string,
//   should_send_message: boolean,
//   conversation_stage: string,  ← vocabulário interno do agente
//   extracted_manager_contact: string|null,
//   extracted_manager_email: string|null,
//   extracted_manager_name: string|null,
//   detected_persona: string|null,
//   persona_confidence: string|null
// }
//
// Mapeamento de stages (FastAPI interno → pipeline SDR):
//   opening / requesting / handling_objection → gathering_decisor
//   success                                   → decisor_captured
//   failed                                    → denied
//
// CHANNEL_SUCCESS: success sem phone nem email
//   → gestor monitora este WhatsApp → usa clinicPhone como contato
// ============================================

const response = $input.first().json;
const payload = $('Prepara Payload FastAPI').first().json;

const body = response.body || response;

const responseMessage = body.response_message || '';
const shouldSendMessage = body.should_send_message === true;
let extractedManagerContact = body.extracted_manager_contact || null;
const extractedManagerEmail = body.extracted_manager_email || null;
const extractedManagerName = body.extracted_manager_name || null;
const detectedPersona = body.detected_persona || payload.detectedPersona || null;
const personaConfidence = body.persona_confidence || payload.personaConfidence || null;

// Traduz stage interno do GatekeeperAgent para stage do pipeline SDR
const stageMap = {
  'opening': 'gathering_decisor',
  'requesting': 'gathering_decisor',
  'handling_objection': 'gathering_decisor',
  'success': 'decisor_captured',
  'failed': 'denied'
};
const rawStage = body.conversation_stage || 'requesting';
const conversationStage = stageMap[rawStage] || 'gathering_decisor';

// CHANNEL_SUCCESS: success sem phone nem email
// O gestor monitora este WhatsApp — usa clinicPhone como contato do canal
// Remove @s.whatsapp.net para salvar número limpo em clinic_decisors
const isChannelSuccess = rawStage === 'success' && !extractedManagerContact && !extractedManagerEmail;
if (isChannelSuccess) {
  extractedManagerContact = (payload.clinicPhone || '').replace('@s.whatsapp.net', '');
}
const contactType = isChannelSuccess ? 'channel'
  : extractedManagerContact ? 'phone'
  : extractedManagerEmail   ? 'email'
  : null;

return [{
  json: {
    conversationId: payload.conversationId,
    rawStage,
    remoteJid: payload.remoteJid,
    instanceName: payload.instanceName,
    responseMessage,
    shouldSendMessage,
    conversationStage,
    extractedManagerContact,
    extractedManagerEmail,
    extractedManagerName,
    contactType,
    detectedPersona,
    personaConfidence
  }
}];

