// Agrega mensagens e monta prompt para o GLM avaliar a conversa
const messages = $input.all().map(item => item.json);
const gkData = $("Processa Resposta FastAPI").first().json;
const clinicName = $("Prepara Contexto Unificado").first().json.clinicName || "Clínica";
const sdrName = $("Prepara Contexto Unificado").first().json.sdrName || "SDR";

const conversationText = messages
  .filter(msg => msg.content && msg.content.trim())
  .map(msg => {
    const speaker = msg.direction === "outbound" ? sdrName + " (SDR)" : "Recepcionista";
    return speaker + ": " + msg.content.trim();
  })
  .join("\n");

const systemPrompt = "Você é um avaliador de conversas de SDR (Sales Development Rep).\n" +
  "Analise a conversa entre " + sdrName + " (SDR) e uma recepcionista de clínica médica.\n" +
  "Objetivo do SDR: coletar o contato (WhatsApp ou email) do gestor/decisor da clínica.\n\n" +
  "Cenários conhecidos (para referência):\n" +
  "- cooperative: recepcionista cooperativa, passa contato diretamente\n" +
  "- ask_data_then_pass: pede dados da Sofia antes de passar contato\n" +
  "- reverse_contact: pede que Sofia deixe contato para o gestor ligar\n" +
  "- email_only: aceita apenas email\n" +
  "- soft_refusal: evasiva, tenta adiar\n" +
  "- hard_refusal: recusa firme, baseada em política\n\n" +
  "Retorne SOMENTE um JSON válido (sem markdown, sem blocos de código):\n" +
  "IMPORTANTE: quality_score deve ser um número entre 0.0 e 1.0 (ex: 0.3, 0.7, 1.0).\n" +
  "{\n" +
  "  \"quality_score\": 0.0,\n" +
  "  \"outcome_label\": \"SUCCESS\",\n" +
  "  \"outcome_reason\": \"string curta\",\n" +
  "  \"sofia_did_well\": [\"ponto1\"],\n" +
  "  \"sofia_should_improve\": [\"ponto1\"],\n" +
  "  \"is_new_pattern\": false,\n" +
  "  \"suggested_scenario_name\": \"\"\n" +
  "}\n\n" +
  "Valores válidos para outcome_label:\n" +
  "SUCCESS, EMAIL_SUCCESS, GRACEFUL_DENIED, SLOW_EXIT, STUCK, BLOCKED_RISK";

const userMessage = "Stage final do sistema: " + gkData.rawStage + "\nClínica: " + clinicName + "\n\nConversa:\n" + conversationText;

return [{
  json: {
    conversationId: gkData.conversationId,
    remoteJid: $("Prepara Contexto Unificado").first().json.remoteJid || "",
    clinicName,
    rawStage: gkData.rawStage,
    conversationText,
    glmMessages: [
      { role: "system", content: systemPrompt },
      { role: "user", content: userMessage }
    ]
  }
}];

const response = $input.first().json;
const promptData = $("Code - Monta Prompt GLM").first().json;

// Extrai conteúdo da resposta GLM (formato OpenAI-compatible)
const rawContent = response.choices && response.choices[0] && response.choices[0].message
  ? response.choices[0].message.content
  : "";

let evaluation = {};
try {
  // Remove markdown code blocks se o GLM retornar com eles
  const cleaned = rawContent.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim();
  evaluation = JSON.parse(cleaned);
} catch (e) {
  evaluation = {
    quality_score: 0.5,
    outcome_label: "UNSCORED",
    outcome_reason: "Falha ao parsear resposta do GLM: " + rawContent.substring(0, 100),
    sofia_did_well: [],
    sofia_should_improve: [],
    is_new_pattern: false,
    suggested_scenario_name: ""
  };
}

return [{
  json: {
    conversationId: promptData.conversationId,
    remoteJid: promptData.remoteJid || "",
    clinicName: promptData.clinicName,
    rawStage: promptData.rawStage,
    conversationText: promptData.conversationText,
    rawGlmResponse: rawContent,
    qualityScore: Math.min(1.0, Math.max(0.0, evaluation.quality_score !== undefined ? parseFloat(evaluation.quality_score) : 0.5)),
    outcomeLabel: evaluation.outcome_label || "UNSCORED",
    outcomeReason: evaluation.outcome_reason || "",
    sofiaDidWell: JSON.stringify(evaluation.sofia_did_well || []),
    sofiaShoulImprove: JSON.stringify(evaluation.sofia_should_improve || []),
    isNewPattern: evaluation.is_new_pattern || false,
    suggestedScenarioName: evaluation.suggested_scenario_name || ""
  }
}];

