parameters.jsCode:
// Sinaliza isHomolog=true quando sdr_config.environment = 'homolog'.
// Fonte de verdade: sdr_config, lido pelo nó upstream "Supabase - Lê Config".
// Dados da mensagem: Parse Evolution Payload (disponível em qualquer branch).

const config = $input.first().json;                    // saída de "Supabase - Lê Config"
const data   = $('Parse Evolution Payload').first().json; // payload da mensagem

return [{ json: {
  ...data,
  isHomolog: (config.environment || '') === 'homolog'
} }];

// Verifica se a conversa deve ser bloqueada antes de chamar a IA
// Caso 0: paused → operador assumiu o chat, silencia a IA
// Caso 1: opted_out → ignorar completamente
// Caso 2: pending_optout + palavra-chave de encerramento → marcar opted_out
const data = $input.first().json;

if (data.currentStatus === 'opted_out') {
  return [{ json: { ...data, _shouldBlock: true, _blockType: 'opted_out' } }];
}

if (data.currentStatus === 'pending_optout') {
  const msg = (data.messageContent || '').toLowerCase().trim();
  const optOutWords = ['sim', 'não quero', 'nao quero', 'encerrar', 'encerra', 'para', 'pare', 'stop', 'não', 'nao'];
  const confirmed = optOutWords.some(w => msg === w || msg.startsWith(w + ' ') || msg.endsWith(' ' + w));
  if (confirmed) {
    return [{ json: { ...data, _shouldBlock: true, _blockType: 'confirm_optout' } }];
  }
}

return [{ json: { ...data, _shouldBlock: false, _blockType: null } }];

